func merge(arr []int, l, m, r int) {
	len1, len2 := m-l+1, r-m
	left := make([]int, len1)
	right := make([]int, len2)
	for i := 0; i < len1; i++ {
		left[i] = arr[l+i]
	}
	for i := 0; i < len2; i++ {
		right[i] = arr[m+1+i]
	}
	i, j, k := 0, 0, l
	for i < len1 && j < len2 {
		if left[i] <= right[j] {
			arr[k] = left[i]
			i++
		} else {
			arr[k] = right[j]
			j++
		}
		k++
	}
	for i < len1 {
		arr[k] = left[i]
		k++
		i++
	}
	for j < len2 {
		arr[k] = right[j]
		k++
		j++
	}
