	n := len(arr)
	minRun := calcMinRun(n)
	for i := 0; i < n; i += minRun {
		end := i + minRun - 1
		if end > n-1 {
			end = n - 1
		}
		insertionSort(arr, i, end)
	}
	for size := minRun; size < n; size = 2 * size {
		for left := 0; left < n; left += 2 * size {
			mid := left + size - 1
