#define MIN_MERGE 32

int calcMinRun(int n) {
	int r = 0;
	while (n >= MIN_MERGE) {
		r |= (n & 1);
		n >>= 1;
	}
	return n + r;
}

void insertionSort(int arr[], int left, int right) {
	for (int i = left + 1; i <= right; i++) {
		int temp = arr[i];
		int j = i - 1;
		while (j >= left && arr[j] > temp) {
			arr[j + 1] = arr[j];
			j--;
		}
		arr[j + 1] = temp;
	}
}

void merge(int arr[], int l, int m, int r) {
	int len1 = m - l + 1, len2 = r - m;
	int *left = (int *)malloc(len1 * sizeof(int));
	int *right = (int *)malloc(len2 * sizeof(int));
	for (int x = 0; x < len1; x++) left[x] = arr[l + x];
	for (int x = 0; x < len2; x++) right[x] = arr[m + 1 + x];
	int i = 0, j = 0, k = l;
	while (i < len1 && j < len2) {
		if (left[i] <= right[j]) {
			arr[k] = left[i];
			i++;
		} else {
			arr[k] = right[j];
			j++;
		}
		k++;
	}
	while (i < len1) {
		arr[k] = left[i];
		k++;
		i++;
	}
	while (j < len2) {
		arr[k] = right[j];
		k++;
		j++;
	}
	free(left);
	free(right);
}

void timSort(int arr[], int n) {
	int minRun = calcMinRun(n);
	for (int i = 0; i < n; i += minRun) {
		int end = (i + minRun - 1 < n - 1) ? (i + minRun - 1) : (n - 1);
		insertionSort(arr, i, end);
	}
	for (int size = minRun; size < n; size = 2 * size) {
		for (int left = 0; left < n; left += 2 * size) {
			int mid = left + size - 1;
			int right = (left + 2 * size - 1 < n - 1) ? (left + 2 * size - 1) : (n - 1);
			if (mid < right) {
				merge(arr, left, mid, right);
			}
		}
	}
}
